package com.ex;

public class VarEx01 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		// 변수의 선언과 동시에 초기화 했다.
		int year = 0;
		int age = 14;
		
		System.out.println(year);
		System.out.println(age);
		
		// 변수의 값을 변경했다.
		year = year + 2026;
		age = age + 1;
		
		System.out.println(year);
		System.out.println(age);
	}

}
